import numpy as np

class WeightedStump:
    def __init__(self):
        self.feature_idx = None
        self.threshold = None
        self.polarity = None

    def fit(self, X: np.ndarray, y: np.ndarray, weights: np.ndarray) -> 'WeightedStump':
        N, D = X.shape
        best_err = float('inf')
        for feat in range(D):
            vals = np.sort(np.unique(X[:, feat]))
            thresholds = (vals[:-1] + vals[1:]) / 2 if len(vals) > 1 else vals
            for thresh in thresholds:
                for polarity in [1, -1]:
                    preds = np.where(X[:, feat] <= thresh, polarity, -polarity)
                    err = np.sum(weights[preds != y])
                    if err < best_err:
                        best_err = err
                        self.feature_idx = feat
                        self.threshold = thresh
                        self.polarity = polarity
        return self

    def predict(self, X: np.ndarray) -> np.ndarray:
        return np.where(X[:, self.feature_idx] <= self.threshold, self.polarity, -self.polarity)

class AdaBoostClassifier:
    def __init__(self, n_estimators: int = 50):
        self.n_estimators = n_estimators
        self.estimators_ = []
        self.alphas_ = []

    def fit(self, X: np.ndarray, y: np.ndarray) -> 'AdaBoostClassifier':
        N = len(y)
        weights = np.ones(N) / N
        self.estimators_ = []
        self.alphas_ = []

        for _ in range(self.n_estimators):
            stump = WeightedStump()
            stump.fit(X, y, weights)
            preds = stump.predict(X)
            eps = np.sum(weights[preds != y])
            if eps >= 0.5:
                break
            alpha = 0.5 * np.log((1 - eps) / max(eps, 1e-10))
            weights = weights * np.exp(-alpha * y * preds)
            weights /= weights.sum()
            self.estimators_.append(stump)
            self.alphas_.append(alpha)
        return self

    def predict(self, X: np.ndarray) -> np.ndarray:
        scores = sum(a * e.predict(X) for a, e in zip(self.alphas_, self.estimators_))
        return np.sign(scores).astype(int)
